export interface ChatMessage {
    id: string;
    role: 'user' | 'assistant';
    text: string;
    timestamp: number;
}

export interface Feedback {
  id: string;
  userId: string;
  userName: string;
  userEmail: string;
  type: 'Improvement' | 'Bug' | 'Technical Issue';
  message: string;
  timestamp: number;
  status: 'New' | 'Read' | 'Resolved';
}

