interface AppContextType {
  // Auth State
  currentUser: UserProfile | null;
  allUsers: UserProfile[]; // For Super Admin

  // App Data
  posts: SocialPost[];
  campaigns: Campaign[];
  messages: IncomingMessage[];
  restrictedTerms: string[];
  brandVoice: BrandVoiceSettings;
  integrations: Integration[];
  currentPlan: BillingPlan;
  mentions: BrandMention[];
  competitors: Competitor[];
  transactions: Transaction[];
  feedbacks: Feedback[];
  adminGateways: AdminGateway[];

  // Actions
  login: (email: string) => void;
  logout: () => void;
  register: (name: string, email: string, company: string) => void;
  processSubscription: (planName: string, provider: PaymentProvider) => Promise<void>;

  // User Actions
  updateUserProfile: (data: Partial<UserProfile>) => void;

  // Super Admin Actions
  suspendUser: (userId: string) => void;
  deleteUser: (userId: string) => void;
  loginAsUser: (userId: string) => void;
  updateFeedbackStatus: (id: string, status: 'Read' | 'Resolved') => void;
  configureAdminGateway: (provider: PaymentProvider, data: any) => Promise<void>;

  // Standard Actions
  addPost: (post: SocialPost) => void;
  updatePostStatus: (id: string, status: PostStatus) => void;
  updatePostContent: (id: string, content: string) => void;
  schedulePost: (id: string, time: number) => void;
  deletePost: (id: string) => void;
  addCampaign: (campaign: Campaign) => void;

  addRestrictedTerm: (term: string) => void;
  removeRestrictedTerm: (term: string) => void;
  updateBrandVoice: (settings: BrandVoiceSettings) => void;
  toggleIntegration: (id: string) => void;
  testIntegration: (id: string) => void;
  sendMessageReply: (id: string, reply: string) => void;
  submitFeedback: (type: 'Improvement' | 'Bug' | 'Technical Issue', message: string) => void;

  // AI Actions
  generateContent: (coreMessage: string, options: { platforms: string[], format: ContentFormat }) => Promise<SocialPost[]>;
  generateCampaignPlan: (goal: string, durationDays: number, platforms: string[], trainingData?: { website: string, sampleContent: string }, targetAudience?: string) => Promise<CampaignPostTemplate[]>;
  generateImage: (prompt: string) => Promise<string | null>;
  repurposePost: (originalPost: SocialPost, targetPlatform: string, targetFormat: ContentFormat) => Promise<SocialPost>;

  // Beta Test Helpers
  injectMessage: (message: IncomingMessage) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // Auth
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [allUsers, setAllUsers] = useState<UserProfile[]>(MOCK_USERS);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);

  // App Data
  const [posts, setPosts] = useState<SocialPost[]>(MOCK_POSTS);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [messages, setMessages] = useState<IncomingMessage[]>(MOCK_INCOMING_MESSAGES);
  const [restrictedTerms, setRestrictedTerms] = useState<string[]>(INITIAL_RESTRICTED_TERMS);
  const [brandVoice, setBrandVoice] = useState<BrandVoiceSettings>(DEFAULT_BRAND_VOICE);
  const [integrations, setIntegrations] = useState<Integration[]>(MOCK_INTEGRATIONS);
  const [currentPlan, setCurrentPlan] = useState<BillingPlan>(PLANS[0]); // Default to Starter
  const [mentions] = useState<BrandMention[]>(MOCK_MENTIONS);
  const [competitors] = useState<Competitor[]>(MOCK_COMPETITORS);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>(MOCK_FEEDBACKS);
  const [adminGateways, setAdminGateways] = useState<AdminGateway[]>(MOCK_ADMIN_GATEWAYS);

  // Initial analysis of mock messages
  useEffect(() => {
    const processMessages = async () => {
       const updatedMessages = await Promise.all(messages.map(async (msg) => {
         if (!msg.suggestedReply && msg.status === 'New') {
            const analysis = await GeminiService.analyzeIncomingMessage(msg.content);
            return { ...msg, ...analysis };
         }
         return msg;
       }));
       if (JSON.stringify(updatedMessages) !== JSON.stringify(messages)) {
         setMessages(updatedMessages);
       }
    };
    processMessages();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Mock background scheduler
  useEffect(() => {
    const intervalId = setInterval(() => {
      setPosts(currentPosts => {
        const now = Date.now();
        let hasChanges = false;

        const updatedPosts = currentPosts.map(post => {
          if (post.status === PostStatus.SCHEDULED && post.scheduledTime && post.scheduledTime <= now) {
            hasChanges = true;
            return { ...post, status: PostStatus.PUBLISHED };
          }
          return post;
        });

        return hasChanges ? updatedPosts : currentPosts;
      });
    }, 10000); 

    return () => clearInterval(intervalId);
  }, []);

  // Auth Methods
  const login = (email: string) => {
    const user = allUsers.find(u => u.email === email);
    if (user) {
      setCurrentUser(user);
      const plan = PLANS.find(p => p.name === user.plan);
      if (plan) setCurrentPlan(plan);
    } else {
      alert("User not found. Try 'admin@zentaras.ai' or 'matt@zentaras.ai'");
    }
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const register = (name: string, email: string, company: string) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name,
      email,
      companyName: company,
      role: 'Owner',
      plan: 'Starter',
      status: 'Active',
      joinedDate: Date.now(),
      affiliate: {
         code: `REF-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
         referrals: 0,
         earnings: 0,
         payoutStatus: 'Paid'
      },
      gamification: {
         level: 1,
         points: 0,
         badges: []
      }
    };
    setAllUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
    setCurrentPlan(PLANS[0]);
  };

  const processSubscription = async (planName: string, provider: PaymentProvider) => {
    return new Promise<void>((resolve) => {
      setTimeout(() => {
        const plan = PLANS.find(p => p.name === planName);
        if (plan && currentUser) {
          // Update Plan
          setCurrentPlan(plan);

          // Create Transaction Record
          const newTransaction: Transaction = {
              id: `tx-${Date.now()}`,
              userId: currentUser.id,
              userEmail: currentUser.email,
              amount: plan.price,
              status: 'Succeeded',
              date: Date.now(),
              provider: provider,
              type: 'Subscription'
          };
          setTransactions(prev => [newTransaction, ...prev]);

          // Update User Profile
          const updatedUser = { ...currentUser, plan: plan.name as any };
          setCurrentUser(updatedUser);
          setAllUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));

          // Notify
          alert(`Payment of $${plan.price} successful via ${provider}. You are now on the ${planName} plan.`);
        }
        resolve();
      }, 2000); // Simulate network delay
    });
  };

  const updateUserProfile = (data: Partial<UserProfile>) => {
    if (!currentUser) return;
    const updated = { ...currentUser, ...data };
    setCurrentUser(updated);
    setAllUsers(prev => prev.map(u => u.id === currentUser.id ? updated : u));
  };

  // Super Admin Actions
  const suspendUser = (userId: string) => {
    setAllUsers(prev => prev.map(u => u.id === userId ? { ...u, status: u.status === 'Active' ? 'Suspended' : 'Active' } : u));
  };

  const deleteUser = (userId: string) => {
    setAllUsers(prev => prev.filter(u => u.id !== userId));
  };

  const loginAsUser = (userId: string) => {
    const user = allUsers.find(u => u.id === userId);
    if (user) {
      setCurrentUser(user);
      const plan = PLANS.find(p => p.name === user.plan);
      if (plan) setCurrentPlan(plan);
    }
  };

  const updateFeedbackStatus = (id: string, status: 'Read' | 'Resolved') => {
    setFeedbacks(prev => prev.map(f => f.id === id ? { ...f, status } : f));
  };

  const configureAdminGateway = async (provider: PaymentProvider, data: any) => {
      // Simulate API call
      return new Promise<void>((resolve) => {
          setTimeout(() => {
              setAdminGateways(prev => {
                  // Check if exists
                  const existing = prev.find(g => g.provider === provider);
                  if (existing) {
                      return prev.map(g => g.provider === provider ? { ...g, connected: true, lastSynced: Date.now(), config: data } : g);
                  }
                  return [...prev, { provider, connected: true, lastSynced: Date.now(), config: data }];
              });
              resolve();
          }, 1500);
      });
  };

  // Standard Actions
  const addPost = (post: SocialPost) => {
    const flagged = restrictedTerms
      .filter(term => post.content.toLowerCase().includes(term.toLowerCase()));

    const finalStatus = flagged.length > 0 
      ? PostStatus.NEEDS_REVIEW 
      : (post.status || PostStatus.DRAFT);

    const newPost = {
      ...post,
      flaggedKeywords: flagged,
      status: finalStatus
    };

    // Update gamification points for creating a post
    if (currentUser && currentUser.gamification) {
        const newPoints = currentUser.gamification.points + 10;
        const newLevel = Math.floor(newPoints / 100) + 1;
        const updatedUser = { 
            ...currentUser, 
            gamification: { 
                ...currentUser.gamification, 
                points: newPoints,
                level: newLevel
            } 
        };
        setCurrentUser(updatedUser);
        setAllUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
    }

    setPosts(prev => [newPost, ...prev]);
  };

  const updatePostStatus = (id: string, status: PostStatus) => {
    setPosts(prev => prev.map(p => p.id === id ? { ...p, status } : p));
  };

  const updatePostContent = (id: string, content: string) => {
    setPosts(prev => prev.map(p => p.id === id ? { ...p, content } : p));
  };

  const schedulePost = (id: string, time: number) => {
    setPosts(prev => prev.map(p => 
      p.id === id ? { ...p, status: PostStatus.SCHEDULED, scheduledTime: time } : p
    ));
  };

  const deletePost = (id: string) => {
    setPosts(prev => prev.filter(p => p.id !== id));
  }

  const addCampaign = (campaign: Campaign) => {
    setCampaigns(prev => [...prev, campaign]);
  };

  const addRestrictedTerm = (term: string) => {
    setRestrictedTerms(prev => [...prev, term]);
  };

  const removeRestrictedTerm = (term: string) => {
    setRestrictedTerms(prev => prev.filter(t => t !== term));
  };

  const updateBrandVoice = (settings: BrandVoiceSettings) => {
    setBrandVoice(settings);
  };

  const toggleIntegration = (id: string) => {
    setIntegrations(prev => prev.map(i => i.id === id ? { ...i, connected: !i.connected } : i));
  }

  const testIntegration = (id: string) => {
    // Set status to testing
    setIntegrations(prev => prev.map(i => i.id === id ? { ...i, status: 'testing' } : i));

    // Simulate API call delay
    setTimeout(() => {
        const success = Math.random() > 0.3; // 70% success rate for demo
        const latency = Math.floor(Math.random() * 200) + 20; // 20-220ms latency

        setIntegrations(prev => prev.map(i => i.id === id ? { 
            ...i, 
            status: success ? 'active' : 'error',
            lastChecked: Date.now(),
            latencyMs: latency
        } : i));
    }, 2000);
  }

  const sendMessageReply = (id: string, reply: string) => {
    setMessages(prev => prev.map(m => m.id === id ? { ...m, status: 'Replied', suggestedReply: reply } : m));
  };

  const injectMessage = (message: IncomingMessage) => {
    setMessages(prev => [message, ...prev]);
  };

  const submitFeedback = (type: 'Improvement' | 'Bug' | 'Technical Issue', message: string) => {
    if (!currentUser) return;

    const newFeedback: Feedback = {
      id: `fb-${Date.now()}`,
      userId: currentUser.id,
      userName: currentUser.name,
      userEmail: currentUser.email,
      type,
      message,
      timestamp: Date.now(),
      status: 'New'
    };

    setFeedbacks(prev => [newFeedback, ...prev]);

    // Simulate Email Sending
    console.log(`[Email Simulation] To: support@aixnetwork.net`);
    console.log(`[Email Simulation] Subject: New Feedback: ${type} from ${currentUser.name}`);
    console.log(`[Email Simulation] Body: ${message}`);

    alert("Feedback sent to SuperAdmin and copy sent to support@aixnetwork.net");
  };

  const generateContent = async (coreMessage: string, options: { platforms: string[], format: ContentFormat }): Promise<SocialPost[]> => {
    const generatedData = await GeminiService.generateSocialContent(coreMessage, options.platforms, options.format, brandVoice);

    const newPosts: SocialPost[] = generatedData.map((data: any) => {
        const flagged = restrictedTerms
            .filter(term => data.content.toLowerCase().includes(term.toLowerCase()));

        return {
            id: Math.random().toString(36).substr(2, 9),
            content: data.content,
            platform: data.platform,
            format: options.format,
            visualPrompt: data.visualPrompt,
            voiceScore: data.voiceScore,
            status: flagged.length > 0 ? PostStatus.NEEDS_REVIEW : PostStatus.DRAFT,
            timestamp: Date.now(),
            flaggedKeywords: flagged,
            predictedEngagement: data.predictedEngagement,
            author: "AI Assistant"
        } as SocialPost;
    });

    return newPosts;
  };

  const generateCampaignPlan = async (goal: string, durationDays: number, platforms: string[], trainingData?: { website: string, sampleContent: string }, targetAudience?: string): Promise<CampaignPostTemplate[]> => {
    return await GeminiService.generateCampaignPlan(goal, durationDays, platforms, trainingData, targetAudience);
  };

  const generateImage = async (prompt: string): Promise<string | null> => {
    return await GeminiService.generateImage(prompt);
  };

  const repurposePost = async (originalPost: SocialPost, targetPlatform: string, targetFormat: ContentFormat): Promise<SocialPost> => {
     const generated = await generateContent(originalPost.content, { platforms: [targetPlatform], format: targetFormat });
     if (generated.length > 0) {
        return generated[0];
     }
     throw new Error("Repurpose failed");
  };

  return (
    <AppContext.Provider value={{
      currentUser,
      allUsers,
      posts,
      campaigns,
      messages,
      restrictedTerms,
      brandVoice,
      integrations,
      currentPlan,
      mentions,
      competitors,
      transactions,
      feedbacks,
      adminGateways,
      login,
      logout,
      register,
      processSubscription,
      updateUserProfile,
      suspendUser,
      deleteUser,
      loginAsUser,
      updateFeedbackStatus,
      configureAdminGateway,
      addPost,
      updatePostStatus,
      updatePostContent,
      schedulePost,
      deletePost,
      addCampaign,
      addRestrictedTerm,
      removeRestrictedTerm,
      updateBrandVoice,
      toggleIntegration,
      testIntegration,
      sendMessageReply,
      submitFeedback,
      generateContent,
      generateCampaignPlan,
      generateImage,
      repurposePost,
      injectMessage
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Users, DollarSign, Activity, Search, Shield, MoreVertical, LogIn, Trash2, Ban, CreditCard, ArrowUpRight, ArrowDownLeft, Trophy, Award, TrendingUp, Star, MessageSquare, CheckCircle, Clock, AlertTriangle, Bug, Lightbulb, User, Settings, Save, X, Lock, Loader2, Key } from 'lucide-react';
import clsx from 'clsx';
import { PaymentProvider } from '../types';

interface GatewayConfigModalProps {
    provider: PaymentProvider;
    isOpen: boolean;
    onClose: () => void;
}

const GatewayConfigModal: React.FC<GatewayConfigModalProps> = ({ provider, isOpen, onClose }) => {
    const { configureAdminGateway } = useApp();
    const [loading, setLoading] = useState(false);
    const [publicKey, setPublicKey] = useState('');
    const [secretKey, setSecretKey] = useState('');
    const [webhookSecret, setWebhookSecret] = useState('');

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        // Simulate API delay
        await configureAdminGateway(provider, { publicKey, secretKey, webhookSecret });
        setLoading(false);
        onClose();
        alert(`${provider} configuration updated successfully!`);
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
            <div className="bg-slate-950 border border-slate-700 rounded-xl w-full max-w-md shadow-2xl overflow-hidden">
                <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                    <h3 className="text-xl font-bold text-white flex items-center gap-2">
                        {provider === 'Stripe' ? <CreditCard className="w-5 h-5 text-blue-500" /> : <span className="text-lg font-bold text-blue-500 italic">P</span>}
                        Connect {provider}
                    </h3>
                    <button onClick={onClose}><X className="w-5 h-5 text-slate-400 hover:text-white" /></button>
                </div>
                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">
                            {provider === 'Stripe' ? 'Publishable Key' : 'Client ID'}
                        </label>
                        <div className="relative">
                            <Key className="absolute left-3 top-3 w-4 h-4 text-slate-600" />
                            <input 
                                type="text" 
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none font-mono text-sm"
                                placeholder={provider === 'Stripe' ? 'pk_test_...' : 'client_id_...'}
                                value={publicKey}
                                onChange={e => setPublicKey(e.target.value)}
                                required
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2">
                            {provider === 'Stripe' ? 'Secret Key' : 'Client Secret'}
                        </label>
                        <input 
                            type="password" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-blue-500 outline-none font-mono text-sm"
                            placeholder={provider === 'Stripe' ? 'sk_test_...' : 'client_secret_...'}
                            value={secretKey}
                            onChange={e => setSecretKey(e.target.value)}
                            required
                        />
                    </div>
                    {provider === 'Stripe' && (
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Webhook Secret</label>
                            <input 
                                type="password" 
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-blue-500 outline-none font-mono text-sm"
                                placeholder="whsec_..."
                                value={webhookSecret}
                                onChange={e => setWebhookSecret(e.target.value)}
                            />
                        </div>
                    )}
                    <div className="pt-4 border-t border-slate-800 flex justify-end">
                        <button 
                            type="submit" 
                            disabled={loading}
                            className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-lg font-bold flex items-center gap-2 transition-all"
                        >
                            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                            Save & Connect
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

const SuperAdmin: React.FC = () => {
  const { allUsers, suspendUser, deleteUser, loginAsUser, transactions, feedbacks, updateFeedbackStatus, currentUser, updateUserProfile, adminGateways } = useApp();
  const [activeTab, setActiveTab] = useState<'overview' | 'users' | 'finance' | 'analytics' | 'feedback'>('overview');
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [configGateway, setConfigGateway] = useState<PaymentProvider | null>(null);

  // Admin Profile State
  const [adminName, setAdminName] = useState('');
  const [adminEmail, setAdminEmail] = useState('');

  useEffect(() => {
      if (currentUser) {
          setAdminName(currentUser.name);
          setAdminEmail(currentUser.email);
      }
  }, [currentUser]);

  const handleUpdateAdminProfile = (e: React.FormEvent) => {
      e.preventDefault();
      updateUserProfile({ name: adminName });
      setIsProfileOpen(false);
      alert("Admin profile updated.");
  };

  const totalMRR = allUsers.reduce((acc, user) => {
    return acc + (user.plan === 'Pro' ? 99 : user.plan === 'Growth' ? 29 : 0);
  }, 0);

  const activeUsers = allUsers.filter(u => u.status === 'Active').length;

  // Analytics Calculations
  const totalReferrals = allUsers.reduce((acc, u) => acc + (u.affiliate?.referrals || 0), 0);
  const totalPoints = allUsers.reduce((acc, u) => acc + (u.gamification?.points || 0), 0);
  const topGamers = [...allUsers].sort((a,b) => (b.gamification?.points || 0) - (a.gamification?.points || 0)).slice(0, 5);
  const topAffiliates = [...allUsers].sort((a,b) => (b.affiliate?.earnings || 0) - (a.affiliate?.earnings || 0)).slice(0, 5);

  const stripeGateway = adminGateways.find(g => g.provider === 'Stripe');
  const paypalGateway = adminGateways.find(g => g.provider === 'PayPal');

  return (
    <div className="min-h-screen bg-slate-900 text-white p-4 md:p-8">
      {/* Modals */}
      {configGateway && (
          <GatewayConfigModal 
              provider={configGateway} 
              isOpen={true} 
              onClose={() => setConfigGateway(null)} 
          />
      )}

      {isProfileOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
              <div className="bg-slate-950 border border-slate-700 rounded-xl w-full max-w-md shadow-2xl overflow-hidden">
                  <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                      <h3 className="text-xl font-bold text-white">Admin Profile</h3>
                      <button onClick={() => setIsProfileOpen(false)}><X className="w-5 h-5 text-slate-400 hover:text-white" /></button>
                  </div>
                  <form onSubmit={handleUpdateAdminProfile} className="p-6 space-y-4">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Display Name</label>
                          <input 
                              type="text" 
                              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-purple-500 outline-none"
                              value={adminName}
                              onChange={e => setAdminName(e.target.value)}
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Email (System)</label>
                          <input 
                              type="email" 
                              disabled
                              className="w-full bg-slate-900/50 border border-slate-800 rounded-lg px-4 py-2.5 text-slate-400 cursor-not-allowed"
                              value={adminEmail}
                          />
                      </div>
                      <div className="pt-4 border-t border-slate-800 flex justify-end">
                          <button type="submit" className="bg-purple-600 hover:bg-purple-700 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2">
                              <Save className="w-4 h-4" /> Save Changes
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Admin Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 border-b border-slate-800 pb-6 gap-4">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Shield className="w-6 h-6 text-purple-500" /> Super Admin
          </h1>
          <p className="text-slate-400">Platform Overview & Tenant Management</p>
        </div>
        <div className="flex items-center gap-4">
           <div className="bg-slate-800 px-4 py-2 rounded-lg text-sm text-slate-300 flex items-center gap-2">
              <User className="w-4 h-4 text-purple-400" />
              <span>{currentUser?.name}</span>
           </div>
           <button 
              onClick={() => setIsProfileOpen(true)}
              className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white rounded-lg transition-colors border border-slate-700"
              title="Admin Settings"
           >
               <Settings className="w-5 h-5" />
           </button>
        </div>
      </div>

      <div className="flex gap-4 mb-8 overflow-x-auto pb-2 scrollbar-hide">
        {['Overview', 'Users', 'Finance', 'Analytics', 'Feedback'].map(tab => (
            <button
                key={tab}
                onClick={() => setActiveTab(tab.toLowerCase() as any)}
                className={clsx(
                    "px-4 py-2 rounded-lg font-medium transition-colors whitespace-nowrap",
                    activeTab === tab.toLowerCase() ? "bg-blue-600 text-white" : "bg-slate-800 text-slate-400 hover:text-white"
                )}
            >
                {tab}
                {tab === 'Feedback' && feedbacks.filter(f => f.status === 'New').length > 0 && (
                    <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full font-bold">
                        {feedbacks.filter(f => f.status === 'New').length}
                    </span>
                )}
            </button>
        ))}
      </div>

      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
            <div className="bg-slate-950 border border-slate-800 p-6 rounded-xl">
            <div className="flex justify-between items-start mb-2">
                <p className="text-slate-400 text-xs uppercase font-bold tracking-wider">Total MRR</p>
                <DollarSign className="w-5 h-5 text-emerald-500" />
            </div>
            <h3 className="text-3xl font-bold text-white">${totalMRR.toLocaleString()}</h3>
            <p className="text-xs text-slate-500 mt-1 flex items-center gap-1">
                <ArrowUpRight className="w-3 h-3 text-emerald-500" /> +12% vs last month
            </p>
            </div>

            <div className="bg-slate-950 border border-slate-800 p-6 rounded-xl">
            <div className="flex justify-between items-start mb-2">
                <p className="text-slate-400 text-xs uppercase font-bold tracking-wider">Total Users</p>
                <Users className="w-5 h-5 text-blue-500" />
            </div>
            <h3 className="text-3xl font-bold text-white">{allUsers.length}</h3>
            <p className="text-xs text-slate-500 mt-1">{activeUsers} Active</p>
            </div>

            <div className="bg-slate-950 border border-slate-800 p-6 rounded-xl">
