export const chatWithOnboardingAgent = async (
    userMessage: string,
    history: ChatMessage[],
    userContext: { name: string; plan: string }
): Promise<string> => {
    if (!process.env.API_KEY) return "Zen is in demo mode. Connect an API key to enable full AI chat.";

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `You are Zen, AI Onboarding Specialist for Zentaras. User: ${userContext.name}, Plan: ${userContext.plan}. Keep it helpful and concise.`;

    try {
        const recentHistory = history.slice(-6).map(msg => ({
            role: msg.role === 'user' ? 'user' : 'model',
            parts: [{ text: msg.text }]
        }));

        const chat = ai.chats.create({
            model: FAST_MODEL,
            config: { systemInstruction, temperature: 0.7 },
            history: recentHistory
        });

        const result = await chat.sendMessage({ message: userMessage });
        return result.text || "I'm processing your request.";
    } catch (error) {
        console.error("Onboarding Chat Error:", error);
        return "I'm having a connection issue. Let me know if you need help navigating!";
    }
};

export const generateCampaignPlan = async (
  goal: string,
  durationDays: number,
  platforms: string[],
  trainingData?: { website: string; sampleContent: string },
  targetAudience?: string
): Promise<CampaignPostTemplate[]> => {
  if (!process.env.API_KEY) return getMockCampaignPlan(durationDays, platforms);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Goal: ${goal}. Duration: ${durationDays} days. Audience: ${targetAudience}. Platforms: ${platforms.join(',')}. Output JSON array of {dayOffset, platform, format, intent}.`;

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              dayOffset: { type: Type.INTEGER },
              platform: { type: Type.STRING },
              format: { type: Type.STRING },
              intent: { type: Type.STRING }
            },
            required: ["dayOffset", "platform", "format", "intent"]
          }
        },
      },
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (error) {
    return getMockCampaignPlan(durationDays, platforms);
  }
};

export const generateSocialContent = async (
  coreMessage: string,
  platforms: string[],
  format: ContentFormat,
  voiceSettings: BrandVoiceSettings
): Promise<any[]> => {
  if (!process.env.API_KEY) return getMockSocialContent(coreMessage, platforms, format, voiceSettings);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Topic: "${coreMessage}". Voice: "${voiceSettings.description}". Format: ${format}. Platforms: ${platforms.join(',')}. Output JSON array of {platform, content, voiceScore, predictedEngagement, visualPrompt}.`;

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              platform: { type: Type.STRING },
              content: { type: Type.STRING },
              voiceScore: { type: Type.INTEGER },
              predictedEngagement: { type: Type.STRING },
              visualPrompt: { type: Type.STRING }
            },
            required: ["platform", "content", "voiceScore", "predictedEngagement", "visualPrompt"]
          }
        },
        temperature: 0.8,
      },
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (error) {
    return getMockSocialContent(coreMessage, platforms, format, voiceSettings);
  }
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  if (!process.env.API_KEY) return null;
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    return null;
  }
};

export const analyzeIncomingMessage = async (message: string): Promise<Partial<IncomingMessage>> => {
  if (!process.env.API_KEY) return { sentiment: 'Neutral', riskLevel: 'Low', suggestedReply: "Thanks for messaging!" };
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: `Analyze: "${message}". JSON response: {sentiment, riskLevel, suggestedReply}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sentiment: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            suggestedReply: { type: Type.STRING }
          },
          required: ["sentiment", "riskLevel", "suggestedReply"]
        }
      },
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (error) {
    return { sentiment: 'Neutral', riskLevel: 'Low' };
  }
};

