import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Save, Check, CreditCard, Facebook, Instagram, Linkedin, Twitter, Youtube, Copy, DollarSign, Activity, AlertCircle, Loader2, RefreshCw, Plus, Search, X, Filter, Sparkles, Lock, Shield, User, Camera, Bell, Trash2 } from 'lucide-react';
