        case 'sparkpost': return <span className="font-bold text-[10px] text-orange-500">SP</span>;
        case 'sendgrid': return <span className="font-bold text-[10px] text-blue-400">SG</span>;
        case 'segment': return <span className="font-bold text-[10px] text-emerald-500">Seg</span>;
        case 'mixpanel': return <span className="font-bold text-[10px] text-purple-500">Mix</span>;
        case 'activecampaign': return <span className="font-bold text-[10px] text-blue-600">AC</span>;
        default: return <span className="font-bold">{icon[0].toUpperCase()}</span>;
    }
