interface PaymentModalProps {
  plan: BillingPlan;
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (provider: PaymentProvider) => Promise<void>;
}

const PaymentModal: React.FC<PaymentModalProps> = ({ plan, isOpen, onClose, onConfirm }) => {
  const [provider, setProvider] = useState<PaymentProvider>('Stripe');
  const [loading, setLoading] = useState(false);
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    await onConfirm(provider);
    setLoading(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
        <div className="bg-slate-950 border border-slate-700 rounded-xl w-full max-w-md shadow-2xl overflow-hidden flex flex-col">
            {/* Header */}
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                <div>
                    <h3 className="text-xl font-bold text-white">Upgrade to {plan.name}</h3>
                    <p className="text-slate-400 text-sm">${plan.price}/month • Cancel anytime</p>
                </div>
                <button onClick={onClose}><X className="w-5 h-5 text-slate-400 hover:text-white" /></button>
            </div>

            {/* Provider Toggle */}
            <div className="p-6 pb-0">
                <div className="flex gap-4 mb-6">
                    <button 
                        onClick={() => setProvider('Stripe')}
                        className={clsx(
                            "flex-1 py-3 rounded-xl border flex flex-col items-center justify-center gap-2 transition-all",
                            provider === 'Stripe' ? "bg-indigo-600/10 border-indigo-500 text-white" : "bg-slate-900 border-slate-800 text-slate-400 hover:bg-slate-800"
                        )}
                    >
                        <CreditCard className="w-6 h-6" />
                        <span className="text-xs font-bold">Card</span>
                    </button>
                    <button 
                        onClick={() => setProvider('PayPal')}
                        className={clsx(
                            "flex-1 py-3 rounded-xl border flex flex-col items-center justify-center gap-2 transition-all",
                            provider === 'PayPal' ? "bg-blue-600/10 border-blue-500 text-white" : "bg-slate-900 border-slate-800 text-slate-400 hover:bg-slate-800"
                        )}
                    >
                        <span className="italic font-bold font-serif text-lg">P</span>
                        <span className="text-xs font-bold">PayPal</span>
                    </button>
                </div>
            </div>

            {/* Forms */}
            <div className="p-6 pt-0">
                {provider === 'Stripe' ? (
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Card Number</label>
                            <div className="relative">
                                <CreditCard className="absolute left-3 top-3 w-4 h-4 text-slate-500" />
                                <input 
                                    type="text" 
                                    placeholder="0000 0000 0000 0000" 
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:border-indigo-500 outline-none font-mono text-sm"
                                    value={cardNumber}
                                    onChange={e => setCardNumber(e.target.value)}
                                    required
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Expiry</label>
                                <input 
                                    type="text" 
                                    placeholder="MM/YY" 
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-indigo-500 outline-none font-mono text-center"
                                    value={expiry}
                                    onChange={e => setExpiry(e.target.value)}
                                    required
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">CVC</label>
                                <input 
                                    type="text" 
                                    placeholder="123" 
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-indigo-500 outline-none font-mono text-center"
                                    value={cvc}
                                    onChange={e => setCvc(e.target.value)}
                                    required
                                />
                            </div>
                        </div>
                        <button 
                            type="submit" 
                            disabled={loading}
                            className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 rounded-lg flex items-center justify-center gap-2 mt-4"
                        >
                            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Lock className="w-4 h-4" />}
                            Pay ${plan.price}
                        </button>
                    </form>
                ) : (
                    <div className="text-center py-4">
                        <p className="text-sm text-slate-400 mb-6">You will be redirected to PayPal to complete your purchase safely.</p>
                        <button 
                            onClick={(e) => handleSubmit(e)}
                            disabled={loading}
                            className="w-full bg-[#ffc439] hover:bg-[#f4bb36] text-blue-900 font-bold py-3 rounded-lg flex items-center justify-center gap-2"
                        >
                            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <span>Pay with <span className="italic font-bold">PayPal</span></span>}
                        </button>
                    </div>
                )}
            </div>

            <div className="p-4 bg-slate-900 border-t border-slate-800 text-center">
                <p className="text-[10px] text-slate-500 flex items-center justify-center gap-1">
                    <Shield className="w-3 h-3" /> Secure 256-bit SSL Encrypted Payment
                </p>
            </div>
        </div>
    </div>
  );
}

const Settings: React.FC = () => {
  const { brandVoice, updateBrandVoice, integrations, toggleIntegration, testIntegration, currentPlan, processSubscription, currentUser, updateUserProfile } = useApp();
  const [description, setDescription] = useState(brandVoice.description);
  const [tone, setTone] = useState(brandVoice.tone ?? 50);
  const [activeTab, setActiveTab] = useState<'profile' | 'my brand' | 'connect accounts' | 'subscription' | 'affiliate'>('profile');

  // Profile State
  const [profileName, setProfileName] = useState(currentUser?.name || '');
  const [profileCompany, setProfileCompany] = useState(currentUser?.companyName || '');
  const [profileEmail, setProfileEmail] = useState(currentUser?.email || '');

  // Integration Modal State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<'All' | 'Social' | 'CRM' | 'Productivity' | 'Marketing' | 'Analytics'>('All');

  // Payment Modal State
  const [selectedPlan, setSelectedPlan] = useState<BillingPlan | null>(null);

  // Brand Analysis State
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  useEffect(() => {
      if (currentUser) {
          setProfileName(currentUser.name);
          setProfileCompany(currentUser.companyName);
          setProfileEmail(currentUser.email);
      }
  }, [currentUser]);

  const connectedIntegrations = integrations.filter(i => i.connected);

  const availableIntegrations = integrations.filter(i => 
      !i.connected && 
      i.name.toLowerCase().includes(searchQuery.toLowerCase()) &&
      (activeCategory === 'All' || i.category === activeCategory)
  );

  const handleSaveVoice = () => {
    updateBrandVoice({ ...brandVoice, description, tone });
    alert("Brand Voice Updated!");
  };

  const handleUpdateProfile = (e: React.FormEvent) => {
      e.preventDefault();
      updateUserProfile({ name: profileName, companyName: profileCompany });
      alert("Profile updated successfully");
  };

  const handleAutoDetect = async () => {
    setIsAnalyzing(true);
    // Gather info
    const connectedApps = integrations.filter(i => i.connected).map(i => i.name);
    // Heuristic for website if not explicitly stored: use email domain or company name
    const websiteHint = currentUser?.email.split('@')[1] || currentUser?.companyName || '';

    try {
        const result = await analyzeBrandIdentity(
            currentUser?.companyName || 'My Brand',
            websiteHint,
            connectedApps
        );
        setDescription(result.description);
        setTone(result.tone);
    } catch (e) {
        console.error(e);
        alert("Could not analyze brand automatically. Please fill in details manually.");
    } finally {
        setIsAnalyzing(false);
    }
  };

  const updatePlan = (plan: BillingPlan) => {
      setSelectedPlan(plan);
  }

