                                  <button 
                                      onClick={() => toggleIntegration(app.id)}
                                      className="text-xs bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-1.5 rounded-lg font-bold transition-colors shadow-lg shadow-indigo-900/20"
                                  >
                                      Connect
                                  </button>
                              </div>
                          ))
                      )}
                  </div>
              </div>
          </div>
      )}

      <div>
        <h2 className="text-3xl font-bold text-white mb-2">Settings</h2>
        <p className="text-slate-400">Control how Zentaras works for you.</p>
      </div>

      <div className="flex gap-4 border-b border-slate-800 pb-1 overflow-x-auto">
         {['Profile', 'My Brand', 'Connect Accounts', 'Subscription', 'Affiliate'].map((tab) => (
           <button
             key={tab}
             onClick={() => setActiveTab(tab.toLowerCase() as any)}
             className={clsx(
               "px-4 py-2 font-medium text-sm transition-colors relative whitespace-nowrap",
               activeTab === tab.toLowerCase() 
                 ? "text-indigo-400" 
                 : "text-slate-400 hover:text-slate-200"
             )}
           >
             {tab}
             {activeTab === tab.toLowerCase() && (
               <div className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-500 -mb-1"></div>
             )}
           </button>
         ))}
      </div>

      {/* Profile Tab */}
      {activeTab === 'profile' && (
          <div className="space-y-6">
              <div className="bg-slate-950 border border-slate-800 rounded-xl p-8">
                  <div className="flex flex-col md:flex-row gap-8">
                      {/* Avatar Section */}
                      <div className="flex flex-col items-center gap-4">
                          <div className="w-32 h-32 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 p-1 shadow-2xl">
                              <div className="w-full h-full rounded-full bg-slate-900 flex items-center justify-center text-4xl font-bold text-white overflow-hidden relative group cursor-pointer">
                                  {currentUser?.name.charAt(0)}
                                  <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                                      <Camera className="w-8 h-8 text-white" />
                                  </div>
                              </div>
                          </div>
                          <button className="text-sm font-bold text-indigo-400 hover:text-indigo-300 transition-colors">Change Photo</button>
                      </div>

                      {/* Details Form */}
                      <div className="flex-1 space-y-6">
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Full Name</label>
                                  <div className="relative">
                                      <User className="absolute left-3 top-3 w-4 h-4 text-slate-500" />
                                      <input 
                                          type="text" 
                                          className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:border-indigo-500 outline-none transition-colors"
                                          value={profileName}
                                          onChange={e => setProfileName(e.target.value)}
                                      />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Company Name</label>
                                  <input 
                                      type="text" 
                                      className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:border-indigo-500 outline-none transition-colors"
                                      value={profileCompany}
                                      onChange={e => setProfileCompany(e.target.value)}
                                  />
                              </div>
                              <div className="md:col-span-2">
                                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Email Address</label>
                                  <input 
                                      type="email" 
                                      disabled
                                      className="w-full bg-slate-900/50 border border-slate-800 rounded-lg px-4 py-2.5 text-slate-400 cursor-not-allowed"
                                      value={profileEmail}
                                  />
                                  <p className="text-[10px] text-slate-500 mt-1">Contact support to change your email.</p>
                              </div>
                          </div>

                          <div className="flex justify-end pt-4 border-t border-slate-800">
                              <button 
                                  onClick={handleUpdateProfile}
                                  className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-lg font-bold flex items-center gap-2 transition-all"
                              >
                                  <Save className="w-4 h-4" /> Save Changes
                              </button>
                          </div>
                      </div>
                  </div>
              </div>

              {/* Security Section (Visual Only) */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="bg-slate-950 border border-slate-800 rounded-xl p-6">
                      <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                          <Lock className="w-5 h-5 text-slate-400" /> Security
                      </h3>
                      <div className="space-y-4">
                          <div className="flex justify-between items-center p-3 bg-slate-900 rounded-lg border border-slate-800">
                              <div>
                                  <p className="text-sm font-bold text-white">Password</p>
                                  <p className="text-xs text-slate-500">Last changed 3 months ago</p>
                              </div>
                              <button className="text-xs border border-slate-700 hover:bg-slate-800 text-white px-3 py-1.5 rounded transition-colors">Change</button>
                          </div>
                          <div className="flex justify-between items-center p-3 bg-slate-900 rounded-lg border border-slate-800">
                              <div>
                                  <p className="text-sm font-bold text-white">2FA Authentication</p>
                                  <p className="text-xs text-slate-500">Not enabled</p>
                              </div>
                              <button className="text-xs bg-indigo-900/20 text-indigo-400 border border-indigo-900/50 hover:bg-indigo-900/30 px-3 py-1.5 rounded transition-colors">Enable</button>
                          </div>
                      </div>
                  </div>

                  <div className="bg-slate-950 border border-slate-800 rounded-xl p-6">
                      <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                          <Bell className="w-5 h-5 text-slate-400" /> Notifications
                      </h3>
                      <div className="space-y-3">
                          {['Email digests', 'New feature announcements', 'Security alerts'].map((item, i) => (
                              <div key={i} className="flex items-center justify-between">
                                  <span className="text-sm text-slate-300">{item}</span>
                                  <div className="w-10 h-5 bg-indigo-600 rounded-full relative cursor-pointer">
                                      <div className="absolute right-1 top-1 w-3 h-3 bg-white rounded-full shadow"></div>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              </div>

              {/* Danger Zone */}
              <div className="bg-red-950/10 border border-red-900/30 rounded-xl p-6">
                  <h3 className="text-lg font-bold text-red-400 mb-2 flex items-center gap-2">
                      <Trash2 className="w-5 h-5" /> Danger Zone
                  </h3>
                  <div className="flex justify-between items-center">
                      <p className="text-sm text-slate-400">Permanently delete your account and all data.</p>
                      <button className="text-xs bg-red-950/50 border border-red-900 text-red-400 hover:bg-red-900/50 px-4 py-2 rounded-lg font-bold transition-colors">Delete Account</button>
                  </div>
              </div>
          </div>
      )}

      {/* General Tab: Brand Voice */}
      {activeTab === 'my brand' && (
        <div className="bg-slate-950 border border-slate-800 rounded-xl p-8">
          <h3 className="text-xl font-bold text-white mb-6">Brand Voice & Personality</h3>
          <div className="space-y-6">
            <div>
              <div className="flex justify-between items-end mb-2">
                  <label className="block text-sm font-bold text-slate-400">How should we sound?</label>
                  <button 
                      onClick={handleAutoDetect}
                      disabled={isAnalyzing}
                      className="text-xs flex items-center gap-1 bg-purple-900/30 text-purple-300 border border-purple-500/30 hover:bg-purple-900/50 hover:text-white px-3 py-1.5 rounded-lg transition-all"
                  >
                      {isAnalyzing ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                      Auto-Detect from Socials
                  </button>
              </div>
              <p className="text-xs text-slate-500 mb-3">
                Describe your business tone (e.g., "Professional but friendly," "Exciting and loud," "Calm and helpful"). The AI will copy this style.
              </p>
              <textarea 
                className={clsx(
                    "w-full h-40 bg-slate-900 border rounded-lg p-4 text-slate-200 focus:ring-2 focus:ring-indigo-600 focus:outline-none leading-relaxed transition-all",
                    isAnalyzing ? "border-purple-500/50 animate-pulse" : "border-slate-700"
                )}
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                disabled={isAnalyzing}
                placeholder={isAnalyzing ? "Analyzing your digital footprint..." : "Enter your brand description here..."}
              />
            </div>

            <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
                <div className="flex justify-between items-center mb-4">
                    <label className="block text-sm font-bold text-slate-300">Tone Profile</label>
                    <span className="text-xs font-bold px-2 py-1 rounded bg-indigo-900/30 text-indigo-400 border border-indigo-900/50">
                        {tone < 20 ? 'Very Serious' : tone < 40 ? 'Professional' : tone < 60 ? 'Balanced' : tone < 80 ? 'Casual' : 'Very Playful'}
                    </span>
                </div>
                <div className="flex items-center gap-4">
                    <span className="text-xs text-slate-500 font-bold uppercase tracking-wider">Serious</span>
                    <div className="relative flex-1 h-2 bg-slate-800 rounded-full">
                        <div 
                            className="absolute top-0 left-0 h-full bg-gradient-to-r from-indigo-600 to-purple-600 rounded-full transition-all duration-500" 
                            style={{ width: `${tone}%` }}
                        ></div>
                        <input 
                            type="range" 
                            min="0" 
                            max="100" 
                            value={tone} 
                            onChange={(e) => setTone(Number(e.target.value))}
                            className="absolute top-0 left-0 w-full h-full opacity-0 cursor-pointer"
                        />
                        <div 
                            className="absolute top-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-lg border-2 border-purple-600 pointer-events-none transition-all duration-500"
                            style={{ left: `calc(${tone}% - 8px)` }}
                        ></div>
                    </div>
                    <span className="text-xs text-slate-500 font-bold uppercase tracking-wider">Playful</span>
                </div>
            </div>

            <div className="flex justify-end pt-4">
              <button 
                onClick={handleSaveVoice}
                className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-lg font-medium flex items-center gap-2"
              >
                <Save className="w-4 h-4" /> Save Preferences
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Integrations Tab */}
      {activeTab === 'connect accounts' && (
        <div className="space-y-6">
           <div className="bg-slate-950 border border-slate-800 rounded-xl p-8 min-h-[500px]">
             <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
                <div>
                    <h3 className="text-xl font-bold text-white mb-1">Connected Apps</h3>
                    <p className="text-slate-400 text-sm">Manage your active social media and tool connections.</p>
                </div>
                <div className="flex gap-3">
                    <button className="text-xs bg-slate-900 border border-slate-700 text-slate-300 px-3 py-2 rounded-lg hover:bg-slate-800 flex items-center gap-2 font-bold transition-colors">
                        <RefreshCw className="w-3 h-3" /> Check Health
                    </button>
                    <button 
                        onClick={() => setIsAddModalOpen(true)}
                        className="text-xs bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 flex items-center gap-2 font-bold transition-colors shadow-lg shadow-indigo-900/20"
                    >
                        <Plus className="w-4 h-4" /> Add Integration
                    </button>
                </div>
             </div>

             {connectedIntegrations.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-16 text-center border-2 border-dashed border-slate-800 rounded-xl bg-slate-900/20">
                     <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mb-4">
                         <Filter className="w-8 h-8 text-slate-500" />
                     </div>
                     <h3 className="text-lg font-bold text-white mb-2">No apps connected</h3>
                     <p className="text-slate-500 max-w-sm mb-6">Connect your social media accounts to start publishing and analyzing content.</p>
                     <button 
                        onClick={() => setIsAddModalOpen(true)}
                        className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-lg font-bold flex items-center gap-2 transition-all"
                    >
                        <Plus className="w-4 h-4" /> Connect First App
                    </button>
                 </div>
             ) : (
                <div className="grid grid-cols-1 gap-4">
                {connectedIntegrations.map(app => (
                    <div key={app.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-5 bg-slate-900/50 rounded-xl border border-slate-800 hover:border-slate-700 transition-all gap-4 group">
                        <div className="flex items-center gap-5">
                        <div className="w-12 h-12 rounded-xl bg-slate-950 flex items-center justify-center text-slate-300 border border-slate-800 shadow-sm overflow-hidden">
                            {renderIntegrationIcon(app.icon)}
                        </div>
                        <div>
                            <div className="flex items-center gap-2">
                                <h4 className="font-bold text-white text-base">{app.name}</h4>
                                <span className={clsx(
                                    "px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border",
                                    app.status === 'active' ? "bg-emerald-950/30 border-emerald-900 text-emerald-500" :
                                    app.status === 'error' ? "bg-red-950/30 border-red-900 text-red-500" :
                                    "bg-yellow-950/30 border-yellow-900 text-yellow-500"
                                )}>
                                    {app.status || 'Unknown'}
                                </span>
                            </div>
                            <div className="flex items-center gap-3 mt-1.5">
                                {app.latencyMs && (
                                    <span className="text-[10px] text-slate-500 flex items-center gap-1">
                                        <Activity className="w-3 h-3" /> {app.latencyMs}ms latency
                                    </span>
                                )}
                                <span className="text-[10px] text-slate-600 flex items-center gap-1">
                                    <RefreshCw className="w-3 h-3" /> Sync: {app.lastChecked ? new Date(app.lastChecked).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : 'Never'}
                                </span>
                            </div>
                        </div>
                        </div>

                        <div className="flex items-center gap-3 w-full md:w-auto pl-16 md:pl-0">
                            <button 
                                onClick={() => testIntegration(app.id)}
                                disabled={app.status === 'testing'}
                                className="px-4 py-2 rounded-lg text-xs font-bold transition-colors border bg-slate-950 border-slate-800 text-slate-400 hover:text-white hover:border-slate-600 flex items-center gap-2 disabled:opacity-50"
                            >
                                {app.status === 'testing' ? <Loader2 className="w-3 h-3 animate-spin" /> : <Activity className="w-3 h-3" />}
                                Test
                            </button>

                            <button 
                                onClick={() => toggleIntegration(app.id)}
                                className="px-4 py-2 rounded-lg text-xs font-bold transition-colors border bg-slate-950 border-slate-800 text-red-400 hover:bg-red-950/30 hover:border-red-900/50"
                            >
                                Disconnect
                            </button>
                        </div>
                    </div>
                ))}
                </div>
             )}
           </div>
        </div>
      )}

      {/* Billing Tab */}
      {activeTab === 'subscription' && (
         <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               {PLANS.map(plan => (
                 <div 
                   key={plan.name} 
                   className={clsx(
                     "border rounded-xl p-6 relative flex flex-col cursor-pointer transition-all",
                     currentPlan.name === plan.name 
                       ? "bg-indigo-900/10 border-indigo-500 shadow-lg shadow-indigo-900/20" 
                       : "bg-slate-950 border-slate-800 hover:border-slate-700"
                   )}
                   onClick={() => updatePlan(plan)}
                 >
                    {currentPlan.name === plan.name && (
                      <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs font-bold px-3 py-1 rounded-bl-lg rounded-tr-lg">
                        Current Plan
                      </div>
                    )}
                    <h3 className="text-xl font-bold text-white">{plan.name}</h3>
                    <div className="mt-2 mb-6">
                       <span className="text-3xl font-bold text-white">${plan.price}</span>
                       <span className="text-slate-500">/mo</span>
                    </div>
                    <ul className="space-y-3 mb-8 flex-1">
                       {plan.features.map(feat => (
                         <li key={feat} className="flex items-center gap-2 text-sm text-slate-300">
                           <Check className="w-4 h-4 text-emerald-500" /> {feat}
                         </li>
                       ))}
                    </ul>
                    <button 
                      className={clsx(
                        "w-full py-2 rounded-lg font-bold text-sm",
                        currentPlan.name === plan.name
                           ? "bg-slate-800 text-slate-400 cursor-default"
                           : "bg-indigo-600 hover:bg-indigo-700 text-white"
                      )}
                    >
                       {currentPlan.name === plan.name ? 'Active' : 'Switch to this plan'}
                    </button>
                 </div>
               ))}
            </div>

            <div className="bg-slate-950 border border-slate-800 rounded-xl p-6">
               <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                 <CreditCard className="w-5 h-5" /> Payment Method
               </h3>
               <div className="flex items-center justify-between p-4 bg-slate-900 rounded-lg">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-8 bg-slate-700 rounded flex items-center justify-center text-xs font-mono text-white">VISA</div>
                     <div>
                        <p className="text-sm font-bold text-white">•••• 4242</p>
                        <p className="text-xs text-slate-500">Expires 12/28</p>
                     </div>
                  </div>
                  <button className="text-sm text-indigo-400 hover:text-indigo-300">Update Card</button>
               </div>
            </div>
         </div>
      )}

      {/* Affiliate Tab */}
      {activeTab === 'affiliate' && currentUser?.affiliate && (
          <div className="space-y-6">
              <div className="bg-gradient-to-r from-emerald-900/20 to-teal-900/20 border border-emerald-800/30 rounded-xl p-8">
                  <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                      <div className="space-y-2">
                          <h3 className="text-2xl font-bold text-white">Share & Earn</h3>
                          <p className="text-slate-300">Earn 30% recurring commission for every customer you refer to Zentaras.</p>
                      </div>
                      <div className="text-center bg-slate-900/50 p-4 rounded-xl border border-slate-700">
                          <p className="text-xs text-slate-400 uppercase font-bold tracking-wider mb-1">Total Earnings</p>
                          <p className="text-3xl font-bold text-emerald-400">${currentUser.affiliate.earnings.toFixed(2)}</p>
                      </div>
                  </div>

                  <div className="mt-8">
                      <label className="block text-sm font-bold text-slate-400 mb-2">Your Referral Link</label>
                      <div className="flex gap-2">
                          <input 
                            readOnly
                            className="flex-1 bg-slate-900 border border-slate-700 rounded-lg p-3 text-slate-300 font-mono text-sm focus:outline-none"
                            value={`https://zentara.ai/join?ref=${currentUser.affiliate.code}`}
                          />
                          <button 
                            onClick={() => alert("Link Copied!")}
                            className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 transition-colors"
                          >
                             <Copy className="w-4 h-4" /> Copy
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Settings;
